function determineActions(
  assignedLabels: AssignedLabels,
  aiClassificationResult: FinalClassification,
  config: FinalDecisionConfig,
  processingSteps: string[]
): {
  determinedActions: string[];
  actionReasoning: string;
  thresholdEvaluation?: ThresholdEvaluation;
} {
  const determinedActions: string[] = [];
  const actionReasons: string[] = [];

  // Get action determination settings with defaults
  const actionSettings = config.actionDetermination || {
    archiveIfBelowThreshold: true,
    markAsReadIfArchived: false,
    applyCustomActions: false,
  };

  // Evaluate archive threshold
  let thresholdEvaluation: ThresholdEvaluation | undefined;

  if (actionSettings.archiveIfBelowThreshold) {
    const thresholdType = config.defaultArchiveThreshold;
    const thresholdValue = config.archiveThresholds[thresholdType];
    const confidence = aiClassificationResult.confidence;
    const belowThreshold = confidence < thresholdValue;

    thresholdEvaluation = {
      thresholdType,
      thresholdUsed: thresholdValue,
      confidenceScore: confidence,
      belowThreshold,
      evaluationReason: `Confidence ${confidence.toFixed(2)} ${belowThreshold ? '<' : '>='} ${thresholdType} threshold ${thresholdValue}`,
    };

    processingSteps.push(
      `Threshold evaluation: ${confidence.toFixed(2)} ${belowThreshold ? 'below' : 'above'} ${thresholdType} (${thresholdValue})`
    );

    if (belowThreshold) {
      determinedActions.push('archive');
      actionReasons.push(`Confidence ${confidence.toFixed(2)} below threshold ${thresholdValue}`);
      processingSteps.push('Action: archive (below threshold)');

      // Mark as read if archiving
      if (actionSettings.markAsReadIfArchived) {
        determinedActions.push('markAsRead');
        actionReasons.push('Mark as read when archiving');
        processingSteps.push('Action: markAsRead (archiving)');
      }
    }
  }

  // Apply custom category-specific actions
  if (actionSettings.applyCustomActions && config.categoryActions) {
    const allCategories = [assignedLabels.primary, ...assignedLabels.secondary];

    for (const category of allCategories) {
      const categoryActions = config.categoryActions[category];
      if (categoryActions && Array.isArray(categoryActions)) {
        for (const action of categoryActions) {
          if (!determinedActions.includes(action)) {
            determinedActions.push(action);
            actionReasons.push(`Category ${category} action: ${action}`);
            processingSteps.push(`Action: ${action} (from category ${category})`);
          }
        }
      }
    }
  }

  const actionReasoning = actionReasons.length > 0 ? actionReasons.join('; ') : 'No actions determined';

  return { determinedActions, actionReasoning, thresholdEvaluation };
}

