/**
 * Classification Pipeline Orchestrator
 *
 * Orchestrates the complete 9-stage classification pipeline with canonical signatures:
 * (email, session, result, config) => void
 *
 * Pipeline Stages:
 * 1. Hard Assertions - Domain-based high-confidence categorization
 * 2. Strong Indicators - Weighted seed scoring with diminishing returns
 * 3. Rule Scoring - Hierarchical pattern matching (high/medium/low tiers)
 * 4. Attribute Detection - Cross-cutting signals (urgency, domains, structural patterns)
 * 5. Attribute Influence - Role-based bonuses (CORE, PRIMARY_BOOST, etc.)
 * 6. Disambiguation - Pairwise conflict resolution for close scores
 * 7. Multi-label Selection - Confidence-based label assignment with co-presence rules
 * 8. AI Routing - Selective AI classification for uncertain cases
 * 9. Final Decision - Label assignment and action determination
 * 10. Audit Trail - Complete explainability trace generation
 */

import { EmailMessage } from '../types/email-message';
import { CategoryConfiguration } from '../types/category-configuration';
import { ClassificationResult } from '../types/classification-result';

// Validation utilities
import { validateEmailInput, validateConfigInput } from '../utils/validation';

// Initialization utilities
import {
  createClassificationSession,
  createClassificationResult,
  incrementSessionSuccess,
  incrementSessionError,
  finalizeClassificationSession,
} from '../utils/initialization';

// Pipeline stages (canonical signatures)
import { executeHardAssertions } from '../stages/hard-assertions';
import { executeStrongIndicators } from '../stages/strong-indicators';
import { executeRuleScoring } from '../stages/rule-scoring';
import { executeAttributeDetection } from '../stages/attribute-detection';
import { executeAttributeInfluence } from '../stages/attribute-influence';
import { executeDisambiguation } from '../stages/disambiguation';
import { executeMultiLabelSelection } from '../stages/multi-label-selection';
import { aiRoutingStage } from '../stages/ai-routing';
import { aiFeatureExtractionStage } from '../stages/ai-feature-extraction';
import { aiClassificationStage } from '../stages/ai-classification';
import { finalDecisionStage } from '../stages/final-decision';
import { actionDeterminationStage } from '../stages/action-determination';
// import { generateAuditTrail } from '../stages/audit-trail'; // TODO: Wire audit trail after PipelineResults refactoring

// Stage-specific config types
import type { HardAssertionStageConfig } from '../stages/hard-assertions';
import type { StrongIndicatorStageConfig } from '../stages/strong-indicators';
import type { RuleScoringStageConfig } from '../stages/rule-scoring';
import type { AttributeDetectionStageConfig } from '../stages/attribute-detection';
import type { MultiLabelConfig, ConfidenceThresholds } from '../stages/types';
import type { AIRoutingConfig } from '../stages/ai-routing';
import type { AIFeatureExtractionConfig } from '../stages/ai-feature-extraction';
import type { AIClassificationConfig } from '../stages/ai-classification';
import type { FinalDecisionConfig } from '../stages/final-decision';
import type { ActionDeterminationConfig } from '../stages/action-determination';
// import type { AuditTrailConfig } from '../stages/audit-trail'; // TODO: Wire audit trail after PipelineResults refactoring

/**
 * Error result for batch processing when individual email fails
 */
export interface ClassificationErrorResult {
  error: Error;
  emailId: string;
  processingDurationMs: number;
}

/**
 * Classification Pipeline orchestrator
 *
 * Manages sequential execution of classification stages with proper context
 * propagation, error handling, and performance tracking.
 */
export class ClassificationPipeline {
  private readonly config: CategoryConfiguration;
  private readonly testMode: boolean;

  /**
   * Initialize classification pipeline with validated configuration
   *
   * @param config - Complete category configuration including processingConfig
   * @param testMode - If true, use timestamp-based session IDs for easier debugging
   * @throws {Error} If configuration validation fails
   */
  constructor(config: CategoryConfiguration, testMode: boolean = false) {
    // Validate processing configuration
    validateConfigInput(config.processingConfig);

    // Validate confidence thresholds specifically
    const { confidenceThresholds } = config.processingConfig;
    if (
      !confidenceThresholds ||
      confidenceThresholds.highConfidence < 0 ||
      confidenceThresholds.mediumConfidence < 0 ||
      confidenceThresholds.lowConfidence < 0 ||
      confidenceThresholds.secondaryLabelMinGap < 0
    ) {
      throw new Error('Invalid confidence thresholds: all values must be non-negative');
    }

    this.config = config;
    this.testMode = testMode;
  }

  /**
   * Get configuration (for testing and future stage integration)
   */
  getConfig(): CategoryConfiguration {
    return this.config;
  }

  /**
   * Extract configuration for hard assertions stage
   */
  private getHardAssertionConfig(): HardAssertionStageConfig {
    return {
      confidenceThresholds: this.config.processingConfig.confidenceThresholds,
      categorySignals: this.config.processingConfig.categorySignals as never, // TODO: Fix type mismatch in Phase 3.6
      domainLookup: {}, // TODO: Implement domain resolution in Phase 3.6
    };
  }

  /**
   * Extract configuration for strong indicators stage
   */
  private getStrongIndicatorConfig(): StrongIndicatorStageConfig {
    return {
      confidenceThresholds: this.config.processingConfig.confidenceThresholds,
      categorySignals: this.config.processingConfig.categorySignals as never, // TODO: Fix type mismatch in Phase 3.6
      domainLookup: {}, // TODO: Implement domain resolution in Phase 3.6
      strongIndicatorBaseWeight: 10, // TODO: Extract from config in Phase 3.6
      diminishingReturnsFactor: 0.5, // TODO: Extract from config in Phase 3.6
    };
  }

  /**
   * Extract configuration for rule scoring stage
   */
  private getRuleScoringConfig(): RuleScoringStageConfig {
    return {
      topLevelCategories: this.config.processingConfig.topLevelCategories,
      settings: this.config.processingConfig.settings.ruleScoring,
      tuningParameters: {
        K_high: 5, // TODO: Extract from config in Phase 3.6
        K_medium: 10, // TODO: Extract from config in Phase 3.6
        K_low: 15, // TODO: Extract from config in Phase 3.6
        M_medium: 0.7, // TODO: Extract from config in Phase 3.6
        M_low: 0.3, // TODO: Extract from config in Phase 3.6
        TAIL_DAMPEN: 0.5, // TODO: Extract from config in Phase 3.6
        TAIL_RATIO_CAP: 0.25, // TODO: Extract from config in Phase 3.6
      },
    };
  }

  /**
   * Extract configuration for attribute detection stage
   */
  private getAttributeDetectionConfig(): AttributeDetectionStageConfig {
    return {
      attributes: this.config.processingConfig.attributes,
      settings: {
        attributeProcessing: this.config.processingConfig.settings.attributeProcessing,
      },
      performanceCache: {}, // Optional performance cache for domain lookups
    };
  }

  /**
   * Extract configuration for multi-label selection stage
   */
  private getMultiLabelConfig(): MultiLabelConfig {
    return {
      maxLabels: this.config.processingConfig.multiLabelPolicy.maxTopLevelLabels,
      minSecondaryConfidence: this.config.processingConfig.multiLabelPolicy.minConfidenceForAdditional,
      allowedCombinations: [], // TODO: Extract from multiLabelPolicy in Phase 3.6
    };
  }

  /**
   * Get confidence thresholds
   */
  private getConfidenceThresholds(): ConfidenceThresholds {
    return this.config.processingConfig.confidenceThresholds;
  }

  /**
   * Extract configuration for AI routing stage
   */
  private getAIRoutingConfig(): AIRoutingConfig {
    return {
      settings: {
        aiRouting: this.config.processingConfig.settings.aiRouting,
      },
      confidenceThresholds: this.config.processingConfig.confidenceThresholds,
    };
  }

  /**
   * Extract configuration for AI feature extraction stage
   */
  private getAIFeatureExtractionConfig(): AIFeatureExtractionConfig {
    const openaiApiKey = process.env.OPENAI_API_KEY || '';
    if (!openaiApiKey) {
      throw new Error('OPENAI_API_KEY environment variable is required for AI feature extraction');
    }

    return {
      openai: {
        apiKey: openaiApiKey,
        model: 'gpt-4o-mini',
        temperature: 0.0,
        responseFormat: 'json_schema',
      },
      prompts: this.config.processingConfig.aiPrompts.featureExtraction,
      featureExtractionSchema: {
        name: 'email_feature_extraction',
        description: 'Extract semantic features from email content',
        schema: this.config.processingConfig.featureExtractionSchema as unknown as Record<string, unknown>,
        strict: true,
      },
      retryPolicy: {
        maxRetries: 3,
        backoffMs: 1000,
      },
    };
  }

  /**
   * Extract configuration for AI classification stage
   */
  private getAIClassificationConfig(): AIClassificationConfig {
    const openaiApiKey = process.env.OPENAI_API_KEY || '';
    if (!openaiApiKey) {
      throw new Error('OPENAI_API_KEY environment variable is required for AI classification');
    }

    return {
      openai: {
        apiKey: openaiApiKey,
        model: 'gpt-4o-mini',
        temperature: 0.0,
        responseFormat: 'json_schema',
      },
      prompts: this.config.processingConfig.aiPrompts.finalClassification,
      classificationSchema: {
        name: 'email_classification',
        description: 'Classify email into categories',
        schema: {
          type: 'object',
          properties: {
            primaryCategory: { type: 'string' },
            secondaryCategories: { type: 'array', items: { type: 'string' } },
            confidence: { type: 'number' },
            reasoning: { type: 'string' },
          },
          required: ['primaryCategory', 'secondaryCategories', 'confidence', 'reasoning'],
        },
        strict: true,
      },
      skipConditions: {
        highConfidenceThreshold: this.config.processingConfig.settings.aiRouting.highConfidenceThreshold,
        skipReasons: this.config.processingConfig.settings.aiRouting.skipAiConditions,
      },
      retryPolicy: {
        maxRetries: 3,
        backoffMs: 1000,
      },
    };
  }

  /**
   * Extract configuration for final decision stage (AI label filtering)
   */
  private getFinalDecisionConfig(): FinalDecisionConfig {
    return {
      labelAssignmentRules: {
        maxLabels: this.config.processingConfig.multiLabelPolicy.maxTopLevelLabels,
        minSecondaryConfidence: this.config.processingConfig.multiLabelPolicy.minConfidenceForAdditional,
        allowedCombinations: [],
      },
    };
  }

  /**
   * Extract configuration for action determination stage
   */
  private getActionDeterminationConfig(): ActionDeterminationConfig {
    return {
      archiveThresholds: {
        lowImportance: 0.3,
        mediumImportance: 0.5,
        highImportance: 0.7,
      },
      defaultArchiveThreshold: 'mediumImportance',
      actionSettings: {
        archiveIfBelowThreshold: true,
        markAsReadIfArchived: false,
        applyCustomActions: false,
      },
    };
  }

  /**
   * Execute classification pipeline on single email
   *
   * Orchestrates all 9 stages sequentially with proper context propagation:
   * 1. Creates session and result objects using initialization utilities
   * 2. Executes stages 1-7 with canonical signatures
   * 3. Propagates result object through all stages (each stage mutates it)
   * 4. Returns final result object after all stages complete
   *
   * @param email - Email message to classify
   * @returns Complete classification result with selected labels
   * @throws {Error} If email validation fails or any stage throws unrecoverable error
   */
  async classify(email: EmailMessage): Promise<ClassificationResult> {
    const pipelineStartTime = Date.now();

    try {
      // Validate email input
      validateEmailInput(email);

      // Create classification session for single email
      const session = createClassificationSession(this.config.processingConfig, 'sequential', 1, this.testMode);

      // Create classification result
      const result = createClassificationResult(email.id, session.id, 0);

      // Execute pipeline stages sequentially (stages 1-7 implemented)
      // Each stage mutates result object in place

      // Stage 1: Hard Assertions
      executeHardAssertions(email, session, result, this.getHardAssertionConfig());

      // Stage 2: Strong Indicators
      executeStrongIndicators(email, session, result, this.getStrongIndicatorConfig());

      // Stage 3: Rule Scoring
      executeRuleScoring(email, session, result, this.getRuleScoringConfig());

      // Stage 4: Attribute Detection
      executeAttributeDetection(email, session, result, this.getAttributeDetectionConfig());

      // Stage 5: Attribute Influence
      executeAttributeInfluence(email, session, result, this.config);

      // Stage 6: Disambiguation
      executeDisambiguation(email, session, result, this.config);

      // Stage 7: Multi-label Selection
      executeMultiLabelSelection(email, session, result, this.getMultiLabelConfig(), this.getConfidenceThresholds());

      // Stage 8: AI Routing - Determine if AI classification is needed
      aiRoutingStage(email, session, result, this.getAIRoutingConfig());

      // Stages 8a-c: Conditional AI Classification Pipeline
      if (result.needsAiClassification) {
        // Stage 8a: AI Feature Extraction
        await aiFeatureExtractionStage(email, session, result, this.getAIFeatureExtractionConfig());

        // Stage 8b: AI Classification
        await aiClassificationStage(email, session, result, this.getAIClassificationConfig());

        // Stage 8c: Final Decision (merge rule-based and AI results)
        await finalDecisionStage(email, session, result, this.getFinalDecisionConfig());
      }

      // TODO: Stage 9 (audit trail) will be wired after PipelineResults refactoring
      // For now, mark session as successful
      incrementSessionSuccess(session);
      finalizeClassificationSession(session);

      // Update final processing time
      result.processingDurationMs = Date.now() - pipelineStartTime;
      result.processedAt = new Date();

      return result;
    } catch (error) {
      // Capture error with processing time
      const pipelineEndTime = Date.now();
      throw new Error(
        `Classification pipeline failed for email ${email.id} after ${pipelineEndTime - pipelineStartTime}ms: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Process multiple emails sequentially with shared session context
   *
   * @param emails - Array of email messages to classify
   * @returns Array of classification results or error results
   */
  async classifyBatch(emails: EmailMessage[]): Promise<Array<ClassificationResult | ClassificationErrorResult>> {
    const results: Array<ClassificationResult | ClassificationErrorResult> = [];

    // Create batch session
    const session = createClassificationSession(
      this.config.processingConfig,
      'sequential',
      emails.length,
      this.testMode
    );

    for (let i = 0; i < emails.length; i++) {
      const email = emails[i];
      const startTime = Date.now();
      try {
        // Create result for this email
        const result = createClassificationResult(email.id, session.id, i);

        // Execute pipeline stages sequentially
        executeHardAssertions(email, session, result, this.getHardAssertionConfig());
        executeStrongIndicators(email, session, result, this.getStrongIndicatorConfig());
        executeRuleScoring(email, session, result, this.getRuleScoringConfig());
        executeAttributeDetection(email, session, result, this.getAttributeDetectionConfig());
        executeAttributeInfluence(email, session, result, this.config);
        executeDisambiguation(email, session, result, this.config);
        executeMultiLabelSelection(email, session, result, this.getMultiLabelConfig(), this.getConfidenceThresholds());

        // Stage 8: AI Routing - Determine if AI classification is needed
        aiRoutingStage(email, session, result, this.getAIRoutingConfig());

        // Stages 8a-c: Conditional AI Classification Pipeline
        if (result.needsAiClassification) {
          // Stage 8a: AI Feature Extraction
          await aiFeatureExtractionStage(email, session, result, this.getAIFeatureExtractionConfig());

          // Stage 8b: AI Classification
          await aiClassificationStage(email, session, result, this.getAIClassificationConfig());

          // Stage 8c: Final Decision (merge rule-based and AI results)
          await finalDecisionStage(email, session, result, this.getFinalDecisionConfig());
        }

        // Update processing time and mark successful
        result.processingDurationMs = Date.now() - startTime;
        result.processedAt = new Date();
        incrementSessionSuccess(session);

        results.push(result);
      } catch (error) {
        // Continue processing batch on individual email error
        incrementSessionError(session, email.id, 'pipeline', error instanceof Error ? error.message : String(error));
        results.push({
          error: error instanceof Error ? error : new Error(String(error)),
          emailId: email.id,
          processingDurationMs: Date.now() - startTime,
        });
      }
    }

    // Finalize session after all emails processed
    finalizeClassificationSession(session);

    return results;
  }
}

