      result.confidence = 0.85;

      const startTime = Date.now();
      await actionDeterminationStage(email, session, result, config);
      const endTime = Date.now();

      const processingTime = endTime - startTime;
      expect(processingTime).toBeLessThan(50);
      expect(result.explainabilityTrace.stageTimings.actionDetermination).toBeLessThan(50);
    });

    it('should handle large category action sets efficiently', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const categoryActions: Record<string, string[]> = {};

      // Create large action set
      for (let i = 0; i < 100; i++) {
        categoryActions[`category_${i}`] = [`action_${i}_1`, `action_${i}_2`, `action_${i}_3`];
      }

      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: false,
          markAsReadIfArchived: false,
          applyCustomActions: true,
        },
        categoryActions,
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'category_50';
      result.secondaryCategories = ['category_51', 'category_52'];
      result.confidence = 0.85;

      const startTime = Date.now();
      await actionDeterminationStage(email, session, result, config);
      const endTime = Date.now();

      expect(endTime - startTime).toBeLessThan(100);
      expect(result.determinedActions).toContain('action_50_1');
      expect(result.determinedActions).toContain('action_51_1');
      expect(result.determinedActions).toContain('action_52_1');
    });
  });
});

