/**
 * Unit Tests for Action Determination Stage
 *
 * Tests action determination logic (archive, mark-as-read, custom actions)
 * following TDD approach with canonical signature pattern.
 *
 * Stage 9 of the classification pipeline - determines actions for ALL emails
 * based on confidence thresholds and category-specific rules.
 */

import {
  actionDeterminationStage,
  ActionDeterminationConfig,
  ActionDeterminationConfigSchema,
} from '../../src/stages/action-determination';
import { EmailMessage, ClassificationSession } from '../../src/types';
import { createClassificationResult } from '../../src/utils/initialization';

// Mock data factories
function createMockEmail(overrides: Partial<EmailMessage> = {}): EmailMessage {
  return {
    id: 'test-email-123',
    threadId: 'thread-123',
    from: {
      email: 'sender@example.com',
      name: 'Test Sender',
      raw: 'Test Sender <sender@example.com>',
    },
    to: [
      {
        email: 'recipient@example.com',
        name: 'Test Recipient',
        raw: 'Test Recipient <recipient@example.com>',
      },
    ],
    subject: 'Test Email',
    date: new Date('2025-01-15T10:00:00Z'),
    gmailLabels: ['INBOX', 'UNREAD'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'From', value: 'sender@example.com' },
        { name: 'To', value: 'recipient@example.com' },
        { name: 'Subject', value: 'Test Email' },
      ],
    },
    isProcessed: false,
    processingPriority: 50,
    ...overrides,
  };
}

function createMockSession(overrides: Partial<ClassificationSession> = {}): ClassificationSession {
  return {
    id: 'session-123',
    startedAt: new Date('2025-01-15T10:00:00Z'),
    emailCount: 1,
    successCount: 0,
    errorCount: 0,
    processingMode: 'sequential',
    batchSize: 1,
    performanceMetrics: {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    },
    configVersion: 'test-config-v1',
    configSnapshot: {},
    errors: [],
    warnings: [],
    ...overrides,
  };
}

function createMockConfig(overrides: Partial<ActionDeterminationConfig> = {}): ActionDeterminationConfig {
  return {
    archiveThresholds: {
      lowImportance: 0.3,
      mediumImportance: 0.5,
      highImportance: 0.7,
    },
    defaultArchiveThreshold: 'lowImportance',
    actionSettings: {
      archiveIfBelowThreshold: true,
      markAsReadIfArchived: false,
      applyCustomActions: false,
    },
    categoryActions: {},
    ...overrides,
  };
}

describe('Action Determination Stage', () => {
  describe('Input Validation', () => {
    it('should throw error if email is missing id', async () => {
      const email = createMockEmail({ id: undefined as unknown as string });
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.85;

      await expect(actionDeterminationStage(email, session, result, config)).rejects.toThrow(
        'Invalid email input: id or gmailId is required'
      );
    });

    it('should throw error if session is missing id', async () => {
      const email = createMockEmail();
      const session = createMockSession({ id: undefined as unknown as string });
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.85;

      await expect(actionDeterminationStage(email, session, result, config)).rejects.toThrow(
        'Invalid session input: id or sessionId is required'
      );
    });

    it('should throw error if result is missing', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = null as unknown as any;

      await expect(actionDeterminationStage(email, session, result, config)).rejects.toThrow(
        'Classification result is required'
      );
    });

    it('should throw error if primaryCategory is not set', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      // primaryCategory not set (empty string)
      result.confidence = 0.85;

      await expect(actionDeterminationStage(email, session, result, config)).rejects.toThrow(
        'Cannot determine actions: primaryCategory not set in result'
      );
    });

    it('should throw error if archiveThresholds are missing', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = {
        defaultArchiveThreshold: 'lowImportance',
      } as ActionDeterminationConfig;
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.85;

      await expect(actionDeterminationStage(email, session, result, config)).rejects.toThrow(
        'Invalid configuration: archiveThresholds are required'
      );
    });

    it('should throw error if explainabilityTrace is not initialized', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.85;
      result.explainabilityTrace = null as any; // Force null trace

      await expect(actionDeterminationStage(email, session, result, config)).rejects.toThrow(
        'CRITICAL: explainabilityTrace is not initialized in result object'
      );
    });
  });

  describe('Archive Threshold Evaluation', () => {
    it('should archive when confidence below lowImportance threshold', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.5,
          mediumImportance: 0.7,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'lowImportance',
        actionSettings: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: false,
          applyCustomActions: false,
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'social';
      result.secondaryCategories = [];
      result.confidence = 0.3; // Below 0.5 threshold

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('0.30');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('below threshold');
    });

    it('should NOT archive when confidence above lowImportance threshold', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.5,
          mediumImportance: 0.7,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'lowImportance',
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.secondaryCategories = [];
      result.confidence = 0.85; // Above 0.5 threshold

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).not.toContain('archive');
    });

    it('should use mediumImportance threshold when configured', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.3,
          mediumImportance: 0.6,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'mediumImportance',
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'actionable';
      result.confidence = 0.5; // Below 0.6 threshold but above 0.3

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('0.50');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('below threshold');
    });

    it('should use highImportance threshold when configured', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.3,
          mediumImportance: 0.6,
          highImportance: 0.85,
        },
        defaultArchiveThreshold: 'highImportance',
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.75; // Below 0.85 threshold

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('highImportance');
    });

    it('should handle exact threshold boundary (equal values)', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.5,
          mediumImportance: 0.7,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'lowImportance',
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'social';
      result.confidence = 0.5; // Exactly equal to threshold

      await actionDeterminationStage(email, session, result, config);

      // Should NOT archive (confidence >= threshold)
      expect(result.determinedActions).not.toContain('archive');
    });

    it('should skip archive evaluation when archiveIfBelowThreshold is false', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: false,
          markAsReadIfArchived: false,
          applyCustomActions: false,
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'social';
      result.confidence = 0.1; // Very low confidence

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).not.toContain('archive');
    });
  });

  describe('Mark as Read Action', () => {
    it('should mark as read when archiving if configured', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.5,
          mediumImportance: 0.7,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'lowImportance',
        actionSettings: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: true, // Enabled
          applyCustomActions: false,
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'social';
      result.confidence = 0.3; // Below threshold - will archive

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.determinedActions).toContain('markAsRead');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('Mark as read when archiving');
    });

    it('should NOT mark as read when archiving if disabled', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: false, // Disabled
          applyCustomActions: false,
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'social';
      result.confidence = 0.2; // Below threshold - will archive

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.determinedActions).not.toContain('markAsRead');
    });

    it('should NOT mark as read when NOT archiving', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: true,
          applyCustomActions: false,
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.9; // Above threshold - will NOT archive

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).not.toContain('archive');
      expect(result.determinedActions).not.toContain('markAsRead');
    });
  });

  describe('Custom Category Actions', () => {
    it('should apply custom actions for primary category', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: false, // Disable archive logic
          markAsReadIfArchived: false,
          applyCustomActions: true,
        },
        categoryActions: {
          financial: ['applyLabel:important', 'star'],
          actionable: ['applyLabel:todo'],
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.secondaryCategories = [];
      result.confidence = 0.85;

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('applyLabel:important');
      expect(result.determinedActions).toContain('star');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('Category financial action');
    });

    it('should apply custom actions for secondary categories', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: false,
          markAsReadIfArchived: false,
          applyCustomActions: true,
        },
        categoryActions: {
          financial: ['applyLabel:financial'],
          actionable: ['applyLabel:todo', 'star'],
          travel: ['applyLabel:travel'],
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.secondaryCategories = ['actionable', 'travel'];
      result.confidence = 0.85;

      await actionDeterminationStage(email, session, result, config);

      // Should get actions from all categories
      expect(result.determinedActions).toContain('applyLabel:financial');
      expect(result.determinedActions).toContain('applyLabel:todo');
      expect(result.determinedActions).toContain('star');
      expect(result.determinedActions).toContain('applyLabel:travel');
    });

    it('should skip duplicate actions from multiple categories', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: false,
          markAsReadIfArchived: false,
          applyCustomActions: true,
        },
        categoryActions: {
          financial: ['star', 'applyLabel:important'],
          actionable: ['star', 'applyLabel:todo'], // 'star' duplicated
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.secondaryCategories = ['actionable'];
      result.confidence = 0.85;

      await actionDeterminationStage(email, session, result, config);

      // Should only include 'star' once
      const starCount = result.determinedActions.filter((a) => a === 'star').length;
      expect(starCount).toBe(1);
      expect(result.determinedActions).toContain('applyLabel:important');
      expect(result.determinedActions).toContain('applyLabel:todo');
    });

    it('should skip custom actions when applyCustomActions is false', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: false,
          markAsReadIfArchived: false,
          applyCustomActions: false, // Disabled
        },
        categoryActions: {
          financial: ['applyLabel:important', 'star'],
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.85;

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).not.toContain('applyLabel:important');
      expect(result.determinedActions).not.toContain('star');
    });

    it('should handle missing category actions gracefully', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: false,
          markAsReadIfArchived: false,
          applyCustomActions: true,
        },
        categoryActions: {
          financial: ['star'],
          // 'social' category has no actions defined
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'social';
      result.confidence = 0.85;

      await actionDeterminationStage(email, session, result, config);

      // Should not throw error
      expect(result.determinedActions).toBeDefined();
    });

    it('should handle undefined categoryActions config', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: false,
          markAsReadIfArchived: false,
          applyCustomActions: true,
        },
        categoryActions: undefined, // No categoryActions defined
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.85;

      await actionDeterminationStage(email, session, result, config);

      // Should not throw error
      expect(result.determinedActions).toBeDefined();
    });
  });

  describe('Combined Actions', () => {
    it('should combine archive and custom actions', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.5,
          mediumImportance: 0.7,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'lowImportance',
        actionSettings: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: true,
          applyCustomActions: true,
        },
        categoryActions: {
          social: ['applyLabel:lowPriority'],
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'social';
      result.confidence = 0.3; // Below threshold

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.determinedActions).toContain('markAsRead');
      expect(result.determinedActions).toContain('applyLabel:lowPriority');
    });

    it('should combine all action types correctly', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.5,
          mediumImportance: 0.7,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'lowImportance',
        actionSettings: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: true,
          applyCustomActions: true,
        },
        categoryActions: {
          social: ['applyLabel:social', 'applyLabel:lowPriority'],
          subscriptionContent: ['applyLabel:newsletter'],
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'social';
      result.secondaryCategories = ['subscriptionContent'];
      result.confidence = 0.2; // Below threshold

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.determinedActions).toContain('markAsRead');
      expect(result.determinedActions).toContain('applyLabel:social');
      expect(result.determinedActions).toContain('applyLabel:lowPriority');
      expect(result.determinedActions).toContain('applyLabel:newsletter');
      expect(result.determinedActions.length).toBe(5);
    });
  });

  describe('Explainability and Audit Trail', () => {
    it('should populate explainability trace with action reasoning', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: true,
          applyCustomActions: false,
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'social';
      result.confidence = 0.2;

      await actionDeterminationStage(email, session, result, config);

      expect(result.explainabilityTrace.finalDecisionReason).toBeDefined();
      expect(result.explainabilityTrace.finalDecisionReason).toContain('Actions:');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('Confidence 0.20');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('below threshold');
    });

    it('should append to existing finalDecisionReason', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.85;
      result.explainabilityTrace.finalDecisionReason = 'Previous decision reason';

      await actionDeterminationStage(email, session, result, config);

      expect(result.explainabilityTrace.finalDecisionReason).toContain('Previous decision reason');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('; Actions:');
    });

    it('should handle empty action determination gracefully', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: false,
          markAsReadIfArchived: false,
          applyCustomActions: false,
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.85;

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toEqual([]);
      expect(result.explainabilityTrace.finalDecisionReason).toContain('No actions determined');
    });

    it('should track processing duration in stage timings', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.85;

      await actionDeterminationStage(email, session, result, config);

      expect(result.explainabilityTrace.stageTimings.actionDetermination).toBeDefined();
      expect(result.explainabilityTrace.stageTimings.actionDetermination).toBeGreaterThanOrEqual(0);
      expect(typeof result.explainabilityTrace.stageTimings.actionDetermination).toBe('number');
    });

    it('should update result processingDurationMs', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.85;
      const initialDuration = result.processingDurationMs;

      await actionDeterminationStage(email, session, result, config);

      expect(result.processingDurationMs).toBeGreaterThan(initialDuration);
    });
  });

  describe('Edge Cases and Error Handling', () => {
    it('should handle zero confidence', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'unclassified';
      result.confidence = 0; // Zero confidence

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('archive'); // Below threshold
      expect(result.explainabilityTrace.finalDecisionReason).toContain('0.00');
    });

    it('should handle confidence of 1.0', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 1.0; // Perfect confidence

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).not.toContain('archive'); // Above all thresholds
    });

    it('should handle empty secondary categories', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: false,
          markAsReadIfArchived: false,
          applyCustomActions: true,
        },
        categoryActions: {
          financial: ['star'],
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.secondaryCategories = []; // Empty
      result.confidence = 0.85;

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('star');
    });

    it('should handle undefined actionSettings with defaults', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = {
        archiveThresholds: {
          lowImportance: 0.3,
          mediumImportance: 0.5,
          highImportance: 0.7,
        },
        defaultArchiveThreshold: 'lowImportance',
        // actionSettings undefined
      } as ActionDeterminationConfig;
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.2;

      await actionDeterminationStage(email, session, result, config);

      // Should use default settings: archiveIfBelowThreshold=true
      expect(result.determinedActions).toContain('archive');
    });

    it('should handle non-array category actions gracefully', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: false,
          markAsReadIfArchived: false,
          applyCustomActions: true,
        },
        categoryActions: {
          financial: 'not-an-array' as any, // Invalid type
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.85;

      await actionDeterminationStage(email, session, result, config);

      // Should not throw error, just skip invalid actions
      expect(result.determinedActions).toBeDefined();
    });
  });

  describe('Configuration Validation', () => {
    it('should validate config with Zod schema - valid config', () => {
      const validConfig = {
        archiveThresholds: {
          lowImportance: 0.3,
          mediumImportance: 0.5,
          highImportance: 0.7,
        },
        defaultArchiveThreshold: 'lowImportance',
        actionSettings: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchified: false,
          applyCustomActions: true,
        },
        categoryActions: {
          financial: ['star', 'applyLabel:important'],
        },
      };

      const result = ActionDeterminationConfigSchema.safeParse(validConfig);
      expect(result.success).toBe(true);
    });

    it('should reject config with invalid threshold values', () => {
      const invalidConfig = {
        archiveThresholds: {
          lowImportance: 1.5, // Invalid: > 1
          mediumImportance: 0.5,
          highImportance: 0.7,
        },
        defaultArchiveThreshold: 'lowImportance',
      };

      const result = ActionDeterminationConfigSchema.safeParse(invalidConfig);
      expect(result.success).toBe(false);
    });

    it('should reject config with invalid defaultArchiveThreshold', () => {
      const invalidConfig = {
        archiveThresholds: {
          lowImportance: 0.3,
          mediumImportance: 0.5,
          highImportance: 0.7,
        },
        defaultArchiveThreshold: 'invalidThreshold', // Invalid enum value
      };

      const result = ActionDeterminationConfigSchema.safeParse(invalidConfig);
      expect(result.success).toBe(false);
    });

    it('should accept config with optional fields omitted', () => {
      const minimalConfig = {
        archiveThresholds: {
          lowImportance: 0.3,
          mediumImportance: 0.5,
          highImportance: 0.7,
        },
        defaultArchiveThreshold: 'mediumImportance',
        // actionSettings and categoryActions omitted
      };

      const result = ActionDeterminationConfigSchema.safeParse(minimalConfig);
      expect(result.success).toBe(true);
    });
  });

  describe('Performance Requirements', () => {
    it('should process action determination in under 50ms', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: true,
          applyCustomActions: true,
        },
        categoryActions: {
          financial: ['star', 'applyLabel:important'],
          actionable: ['applyLabel:todo'],
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.secondaryCategories = ['actionable'];
      result.confidence = 0.85;

      const startTime = Date.now();
      await actionDeterminationStage(email, session, result, config);
      const endTime = Date.now();

      const processingTime = endTime - startTime;
      expect(processingTime).toBeLessThan(50);
      expect(result.explainabilityTrace.stageTimings.actionDetermination).toBeLessThan(50);
    });

    it('should handle large category action sets efficiently', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const categoryActions: Record<string, string[]> = {};

      // Create large action set
      for (let i = 0; i < 100; i++) {
        categoryActions[`category_${i}`] = [`action_${i}_1`, `action_${i}_2`, `action_${i}_3`];
      }

      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: false,
          markAsReadIfArchived: false,
          applyCustomActions: true,
        },
        categoryActions,
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'category_50';
      result.secondaryCategories = ['category_51', 'category_52'];
      result.confidence = 0.85;

      const startTime = Date.now();
      await actionDeterminationStage(email, session, result, config);
      const endTime = Date.now();

      expect(endTime - startTime).toBeLessThan(100);
      expect(result.determinedActions).toContain('action_50_1');
      expect(result.determinedActions).toContain('action_51_1');
      expect(result.determinedActions).toContain('action_52_1');
    });
  });
});

