    75→  selectedLabels: SelectedLabel[]; // Detailed label selection with rationale
    76→  candidateScores: Record<string, CandidateScore>; // All category scores from pipeline
    77→  selectionSummary: PipelineSelectionSummary; // Pipeline execution summary
