/**
 * Unit Tests for Action Determination Stage
 *
 * Tests action determination logic (archive, mark-as-read, custom actions)
 * following TDD approach with canonical signature pattern.
 *
 * Stage 9 of the classification pipeline - determines actions for ALL emails
 * based on confidence thresholds and category-specific rules.
 */

import {
  actionDeterminationStage,
  ActionDeterminationConfig,
  ActionDeterminationConfigSchema,
} from '../../src/stages/action-determination';
import { EmailMessage, ClassificationSession } from '../../src/types';
import { ClassificationResult } from '../../src/types/classification-result';
import { createClassificationResult } from '../../src/utils/initialization';

// Mock data factories
function createMockEmail(overrides: Partial<EmailMessage> = {}): EmailMessage {
  return {
    id: 'test-email-123',
    threadId: 'thread-123',
    from: {
      email: 'sender@example.com',
      name: 'Test Sender',
      raw: 'Test Sender <sender@example.com>',
    },
    to: [
      {
        email: 'recipient@example.com',
        name: 'Test Recipient',
        raw: 'Test Recipient <recipient@example.com>',
      },
    ],
    subject: 'Test Email',
    date: new Date('2025-01-15T10:00:00Z'),
    gmailLabels: ['INBOX', 'UNREAD'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'From', value: 'sender@example.com' },
        { name: 'To', value: 'recipient@example.com' },
        { name: 'Subject', value: 'Test Email' },
      ],
    },
    isProcessed: false,
    processingPriority: 50,
    ...overrides,
  };
}

function createMockSession(overrides: Partial<ClassificationSession> = {}): ClassificationSession {
  return {
    id: 'session-123',
    startedAt: new Date('2025-01-15T10:00:00Z'),
    emailCount: 1,
    successCount: 0,
    errorCount: 0,
    processingMode: 'sequential',
    batchSize: 1,
    performanceMetrics: {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    },
    configVersion: 'test-config-v1',
    configSnapshot: {},
    errors: [],
    warnings: [],
    ...overrides,
  };
}

function createMockConfig(overrides: Partial<ActionDeterminationConfig> = {}): ActionDeterminationConfig {
  return {
    archiveThresholds: {
      lowImportance: 0.3,
      mediumImportance: 0.5,
      highImportance: 0.7,
    },
    defaultArchiveThreshold: 'lowImportance',
    actionSettings: {
      archiveIfBelowThreshold: true,
      markAsReadIfArchived: false,
      applyCustomActions: false,
    },
    categoryActions: {},
    ...overrides,
  };
}

describe('Action Determination Stage', () => {
  describe('Input Validation', () => {
    it('should throw error if email is missing id', async () => {
      const email = createMockEmail({ id: undefined as unknown as string });
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.85;

      await expect(actionDeterminationStage(email, session, result, config)).rejects.toThrow(
        'Invalid email input: id or gmailId is required'
      );
    });

    it('should throw error if session is missing id', async () => {
      const email = createMockEmail();
      const session = createMockSession({ id: undefined as unknown as string });
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.85;

      await expect(actionDeterminationStage(email, session, result, config)).rejects.toThrow(
        'Invalid session input: id or sessionId is required'
      );
    });

    it('should throw error if result is missing', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = null as unknown as any;

      await expect(actionDeterminationStage(email, session, result, config)).rejects.toThrow(
        'Classification result is required'
      );
    });

    it('should throw error if primaryCategory is not set', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      // primaryCategory not set (empty string)
      result.confidence = 0.85;

      await expect(actionDeterminationStage(email, session, result, config)).rejects.toThrow(
        'Cannot determine actions: primaryCategory not set in result'
      );
    });

    it('should throw error if archiveThresholds are missing', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = {
        defaultArchiveThreshold: 'lowImportance',
      } as ActionDeterminationConfig;
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.85;

      await expect(actionDeterminationStage(email, session, result, config)).rejects.toThrow(
        'Invalid configuration: archiveThresholds are required'
      );
    });

    it('should throw error if explainabilityTrace is not initialized', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.85;
      result.explainabilityTrace = null as any; // Force null trace

      await expect(actionDeterminationStage(email, session, result, config)).rejects.toThrow(
        'CRITICAL: explainabilityTrace is not initialized in result object'
      );
    });
  });

  describe('Archive Threshold Evaluation', () => {
    it('should archive when confidence below lowImportance threshold', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.5,
          mediumImportance: 0.7,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'lowImportance',
        actionSettings: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: false,
          applyCustomActions: false,
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'social';
      result.secondaryCategories = [];
      result.confidence = 0.3; // Below 0.5 threshold

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('0.30');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('below threshold');
    });

    it('should NOT archive when confidence above lowImportance threshold', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.5,
          mediumImportance: 0.7,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'lowImportance',
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.secondaryCategories = [];
      result.confidence = 0.85; // Above 0.5 threshold

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).not.toContain('archive');
    });

    it('should use mediumImportance threshold when configured', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.3,
          mediumImportance: 0.6,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'mediumImportance',
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'actionable';
      result.confidence = 0.5; // Below 0.6 threshold but above 0.3

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('0.50');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('below threshold');
    });

    it('should use highImportance threshold when configured', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.3,
          mediumImportance: 0.6,
          highImportance: 0.85,
        },
        defaultArchiveThreshold: 'highImportance',
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.75; // Below 0.85 threshold

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('0.75');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('below threshold');
    });

    it('should handle exact threshold boundary (equal values)', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.5,
          mediumImportance: 0.7,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'lowImportance',
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'social';
      result.confidence = 0.5; // Exactly equal to threshold

      await actionDeterminationStage(email, session, result, config);

      // Should NOT archive (confidence >= threshold)
      expect(result.determinedActions).not.toContain('archive');
    });

    it('should skip archive evaluation when archiveIfBelowThreshold is false', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: false,
          markAsReadIfArchived: false,
          applyCustomActions: false,
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'social';
      result.confidence = 0.1; // Very low confidence

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).not.toContain('archive');
    });
  });

  describe('Mark as Read Action', () => {
    it('should mark as read when archiving if configured', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.5,
          mediumImportance: 0.7,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'lowImportance',
        actionSettings: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: true, // Enabled
          applyCustomActions: false,
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'social';
      result.confidence = 0.3; // Below threshold - will archive

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.determinedActions).toContain('markAsRead');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('Mark as read when archiving');
    });

    it('should NOT mark as read when archiving if disabled', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: false, // Disabled
          applyCustomActions: false,
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'social';
      result.confidence = 0.2; // Below threshold - will archive

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.determinedActions).not.toContain('markAsRead');
    });

    it('should NOT mark as read when NOT archiving', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: true,
          applyCustomActions: false,
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.confidence = 0.9; // Above threshold - will NOT archive

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).not.toContain('archive');
      expect(result.determinedActions).not.toContain('markAsRead');
    });
  });

  describe('Custom Category Actions', () => {
    it('should apply custom actions for primary category', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: false, // Disable archive logic
          markAsReadIfArchived: false,
          applyCustomActions: true,
        },
        categoryActions: {
          financial: ['applyLabel:important', 'star'],
          actionable: ['applyLabel:todo'],
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.secondaryCategories = [];
      result.confidence = 0.85;

      await actionDeterminationStage(email, session, result, config);

      expect(result.determinedActions).toContain('applyLabel:important');
      expect(result.determinedActions).toContain('star');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('Category financial action');
    });

    it('should apply custom actions for secondary categories', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionSettings: {
          archiveIfBelowThreshold: false,
          markAsReadIfArchived: false,
          applyCustomActions: true,
        },
        categoryActions: {
          financial: ['applyLabel:financial'],
          actionable: ['applyLabel:todo', 'star'],
          travel: ['applyLabel:travel'],
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.primaryCategory = 'financial';
      result.secondaryCategories = ['actionable', 'travel'];
