      result.confidence = 0.85;

      const startTime = Date.now();
      await actionDeterminationStage(email, session, result, config);
      const endTime = Date.now();

      expect(endTime - startTime).toBeLessThan(100);
      expect(result.determinedActions).toContain('action_50_1');
      expect(result.determinedActions).toContain('action_51_1');
      expect(result.determinedActions).toContain('action_52_1');
    });
  });
});

