    28→      minSecondaryConfidence: z.number().min(0).max(1),
    29→      allowedCombinations: z.array(z.string()),
    30→    })
    31→    .optional(),
    32→});
    33→
    34→// Configuration interface for final decision (AI label filtering)
    35→export interface FinalDecisionConfig {
    36→  labelAssignmentRules?: {
    37→    maxLabels: number;
    38→    minSecondaryConfidence: number;
    39→    allowedCombinations: string[];
    40→  };
    41→}
    42→
    43→// Assigned labels result
    44→export interface AssignedLabels {
    45→  primary: string;
    46→  secondary: string[];
    47→}
    48→
    49→// Filtered label tracking
    50→export interface FilteredLabel {
    51→  category: string;
