    53→  score?: number;
    54→}
    55→
    56→// Complete explainability trace for AI label filtering stage
    57→export interface FinalDecisionExplainabilityTrace {
    58→  aiClassificationInput: FinalClassification;
    59→  labelAssignmentRationale: string;
    60→  filteredLabels?: FilteredLabel[];
    61→  processingSteps: string[];
    62→}
    63→
    64→// Complete stage result interface
    65→export interface FinalDecisionResult {
    66→  assignedLabels: AssignedLabels;
    67→  processingDurationMs: number;
    68→  validationErrors: string[];
    69→  explainabilityTrace: FinalDecisionExplainabilityTrace;
    70→}
    71→
    72→/**
    73→ * Final Decision Stage Implementation
    74→ *
    75→ * Assigns final labels and determines actions based on AI classification results
    76→ * and configuration rules, with complete explainability traces.
    77→ *
    78→ * CANONICAL SIGNATURE: (email, session, result, config) => Promise<void>
    79→ * Mutates result object by storing final decision data
    80→ */
    81→export async function finalDecisionStage(
    82→  email: EmailMessage,
    83→  session: ClassificationSession,
    84→  result: ClassificationResult,
    85→  config: FinalDecisionConfig
    86→): Promise<void> {
    87→  const startTime = Date.now();
    88→  const processingSteps: string[] = [];
    89→
    90→  // Validate inputs
    91→  validateInputs(email, session, result, config);
    92→  processingSteps.push('Input validation completed');
    93→
    94→  // Extract AI classification result from result object
    95→  const aiClassificationResult: FinalClassification = result.aiClassificationResult as FinalClassification;
    96→
    97→  // Assign labels based on AI classification and rules
