   129→/**
   130→ * Generate Audit Trail
   131→ *
   132→ * Consolidates results from all 9 pipeline stages into a complete explainability trace
   133→ * for database persistence and debugging purposes.
   134→ *
   135→ * @param email - Email message being classified
   136→ * @param session - Classification session metadata
   137→ * @param pipelineResults - Results from all 9 pipeline stages
   138→ * @param config - Audit trail configuration
   139→ * @returns Complete audit trail with explainability trace
   140→ */
   141→export function generateAuditTrail(
   142→  email: EmailMessage,
   143→  session: ClassificationSession,
   144→  pipelineResults: PipelineResults,
   145→  config: AuditTrailConfig
   146→): AuditTrailResult {
   147→  const startTime = Date.now();
   148→
   149→  // Validate inputs
   150→  validateInputs(email, session, pipelineResults);
   151→
   152→  // Extract session and email IDs (support both id and legacy _id formats)
   153→  const sessionId = session.id || ((session as unknown as Record<string, unknown>).sessionId as string);
   154→  const emailId = email.id || ((email as unknown as Record<string, unknown>).gmailId as string);
   155→
   156→  // Aggregate stage timings
   157→  const stageTimings = aggregateStageTimings(pipelineResults);
   158→
   159→  // Build parallel execution map
   160→  const parallelExecutionMap = buildParallelExecutionMap(pipelineResults);
   161→
   162→  // Collect configuration references
   163→  const configurationRefs = config.includeConfigurationRefs ? collectConfigurationReferences(pipelineResults) : {};
   164→
   165→  // Generate final decision reason
   166→  const finalDecisionReason = generateFinalDecisionReason(pipelineResults);
   167→
   168→  // Extract alternative categories
   169→  const alternativeCategories = extractAlternativeCategories(pipelineResults);
   170→
   171→  // Convert multi-label selection results to explainability format
   172→  const multiLabelResults = convertMultiLabelResults(pipelineResults.multiLabelSelection);
   173→
   174→  // Convert rule scoring results to category rule results
   175→  const ruleScoringResults = convertRuleScoringResults(
   176→    pipelineResults.ruleScoring.ruleMatches,
   177→    pipelineResults.ruleScoring.categoryScores,
   178→    pipelineResults.ruleScoring.subtypeScores
   179→  );
   180→
   181→  // Build AI routing result
   182→  const aiRoutingResult = buildAIRoutingResult(pipelineResults.aiRouting);
   183→
   184→  // Construct complete explainability trace
   185→  const explainabilityTrace: ExplainabilityTrace = {
   186→    sessionId,
   187→    emailId,
   188→    hardAssertions: pipelineResults.hardAssertions.appliedAssertions,
   189→    strongIndicators: pipelineResults.strongIndicators.appliedIndicators,
   190→    ruleScoring: ruleScoringResults,
   191→    attributeDetection: pipelineResults.attributeDetection.detectedAttributes,
   192→    attributeInfluence: pipelineResults.attributeInfluence.appliedInfluences,
   193→    disambiguation: pipelineResults.disambiguation.adjustments,
   194→    multiLabelSelection: multiLabelResults,
   195→    aiRouting: aiRoutingResult,
   196→    stageTimings,
   197→    parallelExecutionMap,
   198→    configurationRefs,
   199→    finalDecisionReason,
   200→    alternativeCategories,
   201→  };
   202→
   203→  return {
   204→    sessionId,
   205→    emailId,
   206→    explainabilityTrace,
   207→    processingDurationMs: Date.now() - startTime,
   208→  };
   209→}
   210→
   211→/**
   212→ * Validate input parameters
   213→ */
   214→function validateInputs(email: EmailMessage, session: ClassificationSession, pipelineResults: PipelineResults): void {
   215→  validateEmailInput(email);
   216→  validateSessionInput(session);
   217→
   218→  if (!pipelineResults || typeof pipelineResults !== 'object') {
   219→    throw new Error('Invalid pipeline results: object required');
   220→  }
   221→
   222→  // Validate required stages
   223→  const requiredStages = [
   224→    'hardAssertions',
   225→    'strongIndicators',
   226→    'ruleScoring',
   227→    'attributeDetection',
   228→    'attributeInfluence',
   229→    'disambiguation',
   230→    'multiLabelSelection',
   231→    'aiRouting',
   232→    'finalDecision',
   233→  ];
   234→
   235→  for (const stage of requiredStages) {
   236→    if (!pipelineResults[stage as keyof PipelineResults]) {
   237→      throw new Error(`Missing required pipeline stage: ${stage}`);
   238→    }
   239→  }
   240→}
   241→
   242→/**
   243→ * Aggregate stage timings from all pipeline stages
   244→ */
   245→function aggregateStageTimings(pipelineResults: PipelineResults): Record<string, number> {
   246→  return {
   247→    hardAssertions: pipelineResults.hardAssertions.processingDurationMs,
   248→    strongIndicators: pipelineResults.strongIndicators.processingDurationMs,
   249→    ruleScoring: pipelineResults.ruleScoring.processingDurationMs,
   250→    attributeDetection: pipelineResults.attributeDetection.processingDurationMs,
   251→    attributeInfluence: pipelineResults.attributeInfluence.processingDurationMs,
   252→    disambiguation: pipelineResults.disambiguation.processingDurationMs,
   253→    multiLabelSelection: pipelineResults.multiLabelSelection.processingDurationMs,
   254→    aiRouting: pipelineResults.aiRouting.processingDurationMs,
   255→    finalDecision: pipelineResults.finalDecision.processingDurationMs,
   256→  };
   257→}
   258→
   259→/**
   260→ * Build parallel execution map tracking which stages/attributes ran concurrently
   261→ */
   262→function buildParallelExecutionMap(pipelineResults: PipelineResults): Record<string, string[]> {
   263→  const parallelMap: Record<string, string[]> = {};
   264→
   265→  // Track parallel-processed attributes from attribute detection stage
   266→  const parallelAttributes = pipelineResults.attributeDetection.detectedAttributes
   267→    .filter((attr) => attr.parallelProcessed)
   268→    .map((attr) => attr.attribute);
   269→
   270→  if (parallelAttributes.length > 0) {
   271→    parallelMap.attributeDetection = parallelAttributes;
   272→  }
   273→
   274→  return parallelMap;
   275→}
   276→
   277→/**
   278→ * Collect configuration references used throughout the pipeline
   279→ */
   280→function collectConfigurationReferences(pipelineResults: PipelineResults): Record<string, string> {
   281→  const refs: Record<string, string> = {};
   282→
   283→  // Hard assertions config
   284→  if (pipelineResults.hardAssertions.appliedAssertions.length > 0) {
   285→    refs.hardAssertions = 'config.processingConfig.categorySignals.*.hardAssertions';
   286→  }
   287→
   288→  // Strong indicators config
   289→  if (pipelineResults.strongIndicators.appliedIndicators.length > 0) {
   290→    refs.strongIndicators = 'config.processingConfig.categorySignals.*.strongIndicators';
   291→  }
   292→
   293→  // Rule scoring config
   294→  if (Object.keys(pipelineResults.ruleScoring.categoryScores).length > 0) {
   295→    refs.ruleScoring = 'config.processingConfig.topLevelCategories.*.subtypes.*.ruleBasedClassification';
   296→  }
   297→
   298→  // Attribute detection config
   299→  if (pipelineResults.attributeDetection.detectedAttributes.length > 0) {
   300→    refs.attributeDetection = 'config.processingConfig.attributes.detectors';
   301→  }
   302→
   303→  // Attribute influence config
   304→  if (pipelineResults.attributeInfluence.appliedInfluences.length > 0) {
   305→    refs.attributeInfluence = 'config.processingConfig.attributeRelevance';
   306→  }
   307→
   308→  // Disambiguation config
   309→  if (pipelineResults.disambiguation.adjustments.length > 0) {
   310→    refs.disambiguation = 'config.processingConfig.settings.disambiguation.confidenceGapThreshold';
   311→  }
   312→
   313→  // Multi-label selection config
   314→  refs.multiLabelSelection = 'config.processingConfig.multiLabelPolicy';
   315→
   316→  // AI routing config
   317→  refs.aiRouting = 'config.processingConfig.confidenceThresholds';
   318→
   319→  // Final decision config
   320→  refs.finalDecision = 'config.processingConfig.settings.archiveThreshold';
   321→
   322→  return refs;
   323→}
   324→
   325→/**
   326→ * Generate final decision reason summarizing the complete classification pipeline
   327→ */
   328→function generateFinalDecisionReason(pipelineResults: PipelineResults): string {
   329→  const reasons: string[] = [];
   330→
   331→  // Check for hard assertions (highest priority)
   332→  if (pipelineResults.hardAssertions.appliedAssertions.length > 0) {
   333→    const categories = pipelineResults.hardAssertions.appliedAssertions.map((a) => a.category);
   334→    reasons.push(`Hard assertion matched for categories: ${Array.from(new Set(categories)).join(', ')}`);
   335→  }
   336→
   337→  // Check for strong indicators
   338→  if (pipelineResults.strongIndicators.appliedIndicators.length > 0) {
   339→    const categories = pipelineResults.strongIndicators.appliedIndicators.map((i) => i.category);
   340→    reasons.push(`Strong indicators detected for: ${Array.from(new Set(categories)).join(', ')}`);
   341→  }
   342→
   343→  // Include rule scoring results
   344→  const topCategories = Object.entries(pipelineResults.ruleScoring.categoryScores)
   345→    .sort((a, b) => b[1] - a[1])
   346→    .slice(0, 3);
   347→
   348→  if (topCategories.length > 0) {
   349→    const categoryScores = topCategories.map(([cat, score]) => `${cat}:${score.toFixed(1)}`).join(', ');
   350→    reasons.push(`Top rule-based scores: ${categoryScores}`);
   351→  }
   352→
   353→  // Include attribute influences
   354→  if (pipelineResults.attributeInfluence.appliedInfluences.length > 0) {
   355→    const attributeCount = pipelineResults.attributeInfluence.appliedInfluences.length;
   356→    reasons.push(`${attributeCount} attribute bonuses applied`);
   357→  }
   358→
   359→  // Include AI routing decision
   360→  if (pipelineResults.aiRouting.routingDecision !== 'skipAi') {
   361→    reasons.push(`AI classification used: ${pipelineResults.aiRouting.reason}`);
   362→  }
   363→
   364→  // Include final decision (AI label filtering if AI was used)
   365→  const finalLabels = pipelineResults.finalDecision.assignedLabels;
   366→  reasons.push(`Final assignment: primary=${finalLabels.primary}, secondary=[${finalLabels.secondary.join(', ')}]`);
   367→
   368→  // Include action determination (applies to all emails)
   369→  if (pipelineResults.actionDetermination.determinedActions.length > 0) {
   370→    reasons.push(`Actions: ${pipelineResults.actionDetermination.determinedActions.join(', ')}`);
   371→  }
   372→
   373→  return reasons.join('; ');
   374→}
   375→
   376→/**
   377→ * Extract alternative categories that were not selected
   378→ */
   379→function extractAlternativeCategories(pipelineResults: PipelineResults): Array<{
   380→  category: string;
   381→  score: number;
   382→  eliminationReason: string;
   383→}> {
   384→  const alternatives: Array<{
   385→    category: string;
   386→    score: number;
   387→    eliminationReason: string;
   388→  }> = [];
   389→
   390→  const finalPrimary = pipelineResults.finalDecision.assignedLabels.primary;
   391→  const finalSecondary = pipelineResults.finalDecision.assignedLabels.secondary;
   392→  const selectedCategories = [finalPrimary, ...finalSecondary];
   393→
   394→  // Get all categories from rule scoring
   395→  const allCategories = Object.entries(pipelineResults.ruleScoring.categoryScores);
   396→
   397→  for (const [category, score] of allCategories) {
   398→    if (!selectedCategories.includes(category)) {
   399→      let eliminationReason = 'Score below selection threshold';
   400→
   401→      // Check if filtered by multi-label selection
   402→      const filteredLabels = pipelineResults.finalDecision.explainabilityTrace.filteredLabels || [];
   403→      const wasFiltered = filteredLabels.find((f) => f.category === category);
   404→      if (wasFiltered) {
   405→        eliminationReason = wasFiltered.filterReason;
   406→      }
   407→
   408→      alternatives.push({
   409→        category,
   410→        score,
   411→        eliminationReason,
   412→      });
   413→    }
   414→  }
   415→
   416→  // Sort by score descending
   417→  alternatives.sort((a, b) => b.score - a.score);
   418→
   419→  return alternatives;
   420→}
   421→
   422→/**
   423→ * Convert rule evaluation results to category rule results for explainability trace
   424→ */
   425→function convertRuleScoringResults(
   426→  ruleEvaluations: RuleEvaluationResult[] | undefined,
   427→  categoryScores: Record<string, number>,
   428→  _subtypeScores: Record<string, Record<string, number>>
   429→): CategoryRuleResult[] {
   430→  if (!ruleEvaluations || ruleEvaluations.length === 0) {
   431→    return [];
   432→  }
   433→
   434→  // Group rule evaluations by category
   435→  const categoryGroups = new Map<string, RuleEvaluationResult[]>();
   436→  for (const evaluation of ruleEvaluations) {
   437→    const existing = categoryGroups.get(evaluation.category) || [];
   438→    existing.push(evaluation);
   439→    categoryGroups.set(evaluation.category, existing);
   440→  }
   441→
   442→  // Convert each category group to CategoryRuleResult
   443→  const categoryResults: CategoryRuleResult[] = [];
   444→  for (const [categoryCode, evaluations] of Array.from(categoryGroups.entries())) {
   445→    // Aggregate all rule matches across subtypes
   446→    const allRuleMatches: RuleScoringMatch[] = [];
   447→    const subtypeScoresMap: Record<string, SubtypeScore> = {};
   448→
   449→    for (const evaluation of evaluations) {
   450→      // Convert RuleMatch[] to RuleScoringMatch[]
   451→      const scoringMatches: RuleScoringMatch[] = evaluation.matchedRules.map((match) => ({
   452→        ...match,
   453→        tier: (evaluation.tier === 'high'
   454→          ? 'highConfidence'
   455→          : evaluation.tier === 'medium'
   456→            ? 'mediumConfidence'
   457→            : 'lowConfidence') as 'highConfidence' | 'mediumConfidence' | 'lowConfidence',
   458→        values: [match.matchedValue],
   459→        weight: match.ruleWeight,
   460→        ruleId: `${evaluation.category}_${evaluation.subtype}_${match.field}`,
   461→      }));
   462→
   463→      allRuleMatches.push(...scoringMatches);
   464→
   465→      // Build subtype score entry
   466→      subtypeScoresMap[evaluation.subtype] = {
   467→        totalScore: evaluation.cappedScore,
   468→        ruleMatches: scoringMatches,
   469→        aggregationBreakdown: evaluation.reason,
   470→      };
   471→    }
   472→
   473→    // Find the subtype with highest score
   474→    const subtypeEntries = Object.entries(subtypeScoresMap);
   475→    const selectedSubtype =
   476→      subtypeEntries.length > 0
   477→        ? subtypeEntries.reduce(
   478→            (max, [id, score]) => (score.totalScore > max.score ? { id, score: score.totalScore } : max),
   479→            { id: subtypeEntries[0][0], score: subtypeEntries[0][1].totalScore }
   480→          )
   481→        : null;
   482→
   483→    // Get category aggregated score from categoryScores
   484→    const aggregatedScore = categoryScores[categoryCode] || 0;
   485→
   486→    // Build scoring rationale
   487→    const scoringRationale = evaluations.map((e) => e.reason);
   488→
   489→    categoryResults.push({
   490→      categoryCode,
   491→      aggregatedScore,
   492→      subtypeScores: subtypeScoresMap,
   493→      ruleMatches: allRuleMatches,
   494→      scoringRationale,
   495→      selectedSubtypeId: selectedSubtype?.id || null,
   496→      confidence: aggregatedScore / 100, // Convert score to confidence (0-1 range)
   497→    });
   498→  }
   499→
   500→  return categoryResults;
   501→}
   502→
   503→/**
   504→ * Convert multi-label selection results to explainability format
   505→ */
   506→function convertMultiLabelResults(multiLabelResult: MultiLabelSelectionResult): ExplainMultiLabelResult[] {
   507→  return multiLabelResult.selectedLabels.map((label) => ({
   508→    selectedCategories: [label.category],
   509→    rejectedCategories: [],
   510→    coPresenceRulesApplied: [],
   511→    maxLabelsLimit: 1,
   512→    minSecondaryConfidence: 0,
   513→    reason: label.selectionRationale,
   514→  }));
   515→}
   516→
   517→/**
   518→ * Build AI routing result for explainability trace
   519→ */
   520→function buildAIRoutingResult(aiRoutingResult: AIRoutingStageResult): AIRoutingResult | undefined {
   521→  // AI routing is optional - only include if AI was actually used
   522→  if (aiRoutingResult.routingDecision === 'skipAi' && !aiRoutingResult.aiResponse) {
   523→    return {
   524→      routingDecision: aiRoutingResult.routingDecision,
   525→      highConfidenceThreshold: aiRoutingResult.highConfidenceThreshold,
   526→      aiRequiredThreshold: aiRoutingResult.aiRequiredThreshold,
   527→      skipConditions: aiRoutingResult.skipConditions,
   528→      reason: aiRoutingResult.reason,
   529→    };
   530→  }
   531→
   532→  return {
   533→    routingDecision: aiRoutingResult.routingDecision,
   534→    highConfidenceThreshold: aiRoutingResult.highConfidenceThreshold,
   535→    aiRequiredThreshold: aiRoutingResult.aiRequiredThreshold,
   536→    skipConditions: aiRoutingResult.skipConditions,
   537→    aiResponse: aiRoutingResult.aiResponse,
   538→    reason: aiRoutingResult.reason,
   539→  };
   540→}
