/**
 * Unit Tests for AI Label Filtering Stage (T035c)
 *
 * Tests AI label filtering and final label assignment logic following TDD approach.
 * These tests MUST FAIL initially before implementation.
 */

import { aiLabelFilteringStage, AILabelFilteringConfig } from '../../src/stages/ai-label-filtering';
import { EmailMessage, ClassificationSession } from '../../src/types';
import { FinalClassification } from '../../src/stages/ai-classification';
import { createClassificationResult } from '../../src/utils/initialization';

// Mock data factories
function createMockEmail(overrides: Partial<EmailMessage> = {}): EmailMessage {
  return {
    id: 'test-email-123',
    threadId: 'thread-123',
    from: {
      email: 'sender@example.com',
      name: 'Test Sender',
      raw: 'Test Sender <sender@example.com>',
    },
    to: [
      {
        email: 'recipient@example.com',
        name: 'Test Recipient',
        raw: 'Test Recipient <recipient@example.com>',
      },
    ],
    subject: 'Test Email',
    date: new Date('2025-01-15T10:00:00Z'),
    gmailLabels: ['INBOX', 'UNREAD'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'From', value: 'sender@example.com' },
        { name: 'To', value: 'recipient@example.com' },
        { name: 'Subject', value: 'Test Email' },
      ],
    },
    isProcessed: false,
    processingPriority: 50,
    ...overrides,
  };
}

function createMockSession(overrides: Partial<ClassificationSession> = {}): ClassificationSession {
  return {
    id: 'session-123',
    startedAt: new Date('2025-01-15T10:00:00Z'),
    emailCount: 1,
    successCount: 0,
    errorCount: 0,
    processingMode: 'sequential',
    batchSize: 1,
    performanceMetrics: {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    },
    configVersion: 'test-config-v1',
    configSnapshot: {},
    errors: [],
    warnings: [],
    ...overrides,
  };
}

function createMockConfig(overrides: Partial<AILabelFilteringConfig> = {}): AILabelFilteringConfig {
  return {
    labelAssignmentRules: {
      maxLabels: 3,
      minSecondaryConfidence: 0.4,
      allowedCombinations: ['financial+actionable'],
    },
    ...overrides,
  };
}

describe('AI Label Filtering Stage (T035c)', () => {
  describe('Input Validation', () => {
    it('should throw error if email is missing id', async () => {
      const email = createMockEmail({ id: undefined as unknown as string });
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: ['actionable'],
        confidence: 0.85,
        reasoning: 'Test reasoning',
      };

      await expect(aiLabelFilteringStage(email, session, result, config)).rejects.toThrow(
        'Invalid email input: id or gmailId is required'
      );
    });

    it('should throw error if session is missing id', async () => {
      const email = createMockEmail();
      const session = createMockSession({ id: undefined as unknown as string });
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: [],
        confidence: 0.85,
        reasoning: 'Test reasoning',
      };

      await expect(aiLabelFilteringStage(email, session, result, config)).rejects.toThrow(
        'Invalid session input: id or sessionId is required'
      );
    });

    it('should throw error if AI result is invalid', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = null as unknown as FinalClassification;

      await expect(aiLabelFilteringStage(email, session, result, config)).rejects.toThrow(
        'Invalid AI classification result in result object: object required'
      );
    });

    it('should throw error if config is missing', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: [],
        confidence: 0.85,
        reasoning: 'Test reasoning',
      };
      const config = null as unknown as AILabelFilteringConfig;

      await expect(aiLabelFilteringStage(email, session, result, config)).rejects.toThrow('Configuration is required');
    });
  });

  describe('Label Assignment', () => {
    it('should assign primary category label correctly', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: [],
        confidence: 0.85,
        reasoning: 'High confidence financial email',
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.primaryCategory).toBe('financial');
      expect(result.secondaryCategories).toEqual([]);
    });

    it('should assign secondary category labels correctly', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        labelAssignmentRules: {
          maxLabels: 3,
          minSecondaryConfidence: 0.3,
          allowedCombinations: [], // Allow all combinations for this test
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: ['actionable', 'travel'],
        confidence: 0.85,
        reasoning: 'Multi-label classification',
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.primaryCategory).toBe('financial');
      expect(result.secondaryCategories).toEqual(['actionable', 'travel']);
    });

    it('should limit secondary labels to maxLabels', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        labelAssignmentRules: {
          maxLabels: 2,
          minSecondaryConfidence: 0.3,
          allowedCombinations: [],
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: ['actionable', 'travel', 'commerce', 'social'],
        confidence: 0.85,
        reasoning: 'Many categories',
        categoryScores: {
          financial: 15,
          actionable: 12,
          travel: 10,
          commerce: 8,
          social: 6,
        },
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.primaryCategory).toBe('financial');
      expect(result.secondaryCategories.length).toBeLessThanOrEqual(1); // maxLabels = 2, minus primary = 1
    });

    it('should filter secondary labels by minSecondaryConfidence', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        labelAssignmentRules: {
          maxLabels: 3,
          minSecondaryConfidence: 0.6,
          allowedCombinations: [],
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: ['actionable', 'travel'],
        confidence: 0.85,
        reasoning: 'Multi-label with varying confidence',
        categoryScores: {
          financial: 15,
          actionable: 12, // 0.8 confidence (12/15)
          travel: 3, // 0.2 confidence (3/15)
        },
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.primaryCategory).toBe('financial');
      // Only 'actionable' should pass minSecondaryConfidence threshold
      expect(result.secondaryCategories).toEqual(['actionable']);
    });

    it('should validate allowed label combinations', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        labelAssignmentRules: {
          maxLabels: 3,
          minSecondaryConfidence: 0.3,
          allowedCombinations: ['financial+actionable'],
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: ['actionable', 'social'],
        confidence: 0.85,
        reasoning: 'Multi-label classification',
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.primaryCategory).toBe('financial');
      // 'actionable' allowed with financial, but 'social' should be rejected
      expect(result.secondaryCategories).toContain('actionable');
      expect(result.secondaryCategories).not.toContain('social');
    });
  });

  describe('Action Determination', () => {
    it('should determine archive action when confidence below threshold', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.5,
          mediumImportance: 0.7,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'lowImportance',
        actionDetermination: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: false,
          applyCustomActions: false,
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'social',
        secondaryCategories: [],
        confidence: 0.3, // Below lowImportance threshold of 0.5
        reasoning: 'Low confidence classification',
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.explainabilityTrace.finalDecisionReason).toContain('below threshold');
    });

    it('should NOT archive when confidence above threshold', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.5,
          mediumImportance: 0.7,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'lowImportance',
        actionDetermination: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: false,
          applyCustomActions: false,
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: ['actionable'],
        confidence: 0.85, // Above threshold
        reasoning: 'High confidence classification',
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.determinedActions).not.toContain('archive');
    });

    it('should mark as read when archiving if configured', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.5,
          mediumImportance: 0.7,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'lowImportance',
        actionDetermination: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: true,
          applyCustomActions: false,
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'social',
        secondaryCategories: [],
        confidence: 0.3, // Below threshold
        reasoning: 'Low confidence classification',
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.determinedActions).toContain('markAsRead');
    });

    it('should apply custom actions based on category', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionDetermination: {
          archiveIfBelowThreshold: false,
          markAsReadIfArchived: false,
          applyCustomActions: true,
        },
        categoryActions: {
          financial: ['applyLabel:important', 'star'],
          actionable: ['applyLabel:todo'],
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: ['actionable'],
        confidence: 0.85,
        reasoning: 'High confidence multi-label',
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.determinedActions).toContain('applyLabel:important');
      expect(result.determinedActions).toContain('star');
      expect(result.determinedActions).toContain('applyLabel:todo');
    });
  });

  describe('Explainability Trace', () => {
    it('should generate complete explainability trace', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: ['actionable'],
        confidence: 0.85,
        reasoning: 'High confidence financial email',
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.explainabilityTrace).toBeDefined();
      expect(result.explainabilityTrace.finalDecisionReason).toBeDefined();
      expect(result.explainabilityTrace.finalDecisionReason).toBeTruthy();
      expect(result.explainabilityTrace.stageTimings.finalDecision).toBeGreaterThanOrEqual(0);
    });

    it('should track label filtering decisions in explainability', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        labelAssignmentRules: {
          maxLabels: 2,
          minSecondaryConfidence: 0.6,
          allowedCombinations: ['financial+actionable'],
        },
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: ['actionable', 'travel', 'social'],
        confidence: 0.85,
        reasoning: 'Multi-label classification',
        categoryScores: {
          financial: 15,
          actionable: 12,
          travel: 5,
          social: 3,
        },
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.explainabilityTrace.alternativeCategories).toBeDefined();
      expect(result.explainabilityTrace.alternativeCategories.length).toBeGreaterThan(0);
      expect(result.explainabilityTrace.finalDecisionReason.toLowerCase()).toContain('filtered');
    });

    it('should track archive threshold evaluation in explainability', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          lowImportance: 0.5,
          mediumImportance: 0.7,
          highImportance: 0.9,
        },
        defaultArchiveThreshold: 'lowImportance',
      });
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'social',
        secondaryCategories: [],
        confidence: 0.3,
        reasoning: 'Low confidence',
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.explainabilityTrace.finalDecisionReason).toBeDefined();
      expect(result.explainabilityTrace.finalDecisionReason).toContain('0.3');
      expect(result.explainabilityTrace.finalDecisionReason.toLowerCase()).toContain('threshold');
    });
  });

  describe('Edge Cases', () => {
    it('should handle unclassified category gracefully', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'unclassified',
        secondaryCategories: [],
        confidence: 0.5,
        reasoning: 'Could not determine category',
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.primaryCategory).toBe('unclassified');
      expect(result.determinedActions).toBeDefined();
    });

    it('should handle missing categoryScores gracefully', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: ['actionable'],
        confidence: 0.85,
        reasoning: 'No category scores provided',
        // categoryScores is undefined
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.primaryCategory).toBe('financial');
      expect(result.secondaryCategories).toEqual(['actionable']);
    });

    it('should handle empty secondary categories', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: [],
        confidence: 0.85,
        reasoning: 'Single label classification',
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.primaryCategory).toBe('financial');
      expect(result.secondaryCategories).toEqual([]);
    });

    it('should handle missing config properties with defaults', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = {
        archiveThresholds: {
          lowImportance: 0.3,
          mediumImportance: 0.5,
          highImportance: 0.7,
        },
        defaultArchiveThreshold: 'lowImportance',
      } as FinalDecisionConfig;
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: [],
        confidence: 0.85,
        reasoning: 'Test with minimal config',
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.primaryCategory).toBe('financial');
      expect(result.determinedActions).toBeDefined();
    });
  });

  describe('Performance and Metrics', () => {
    it('should track processing duration', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: [],
        confidence: 0.85,
        reasoning: 'Test performance tracking',
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.explainabilityTrace.stageTimings.finalDecision).toBeGreaterThanOrEqual(0);
      expect(typeof result.explainabilityTrace.stageTimings.finalDecision).toBe('number');
    });

    it('should track alternative categories for rejected labels', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const result = createClassificationResult('test-email-123', 'session-123', 0);
      result.aiClassificationResult = {
        primaryCategory: 'financial',
        secondaryCategories: ['invalidCategory', 'actionable'],
        confidence: 0.85,
        reasoning: 'Test with invalid category',
      };

      await aiLabelFilteringStage(email, session, result, config);

      expect(result.explainabilityTrace.alternativeCategories).toBeDefined();
      expect(Array.isArray(result.explainabilityTrace.alternativeCategories)).toBe(true);
    });
  });
});

